import { anthropic } from "@ai-sdk/anthropic";
import { aiSystemPrompt } from "@/lib/data";
import { convertToModelMessages, streamText, UIMessage } from "ai";

// Allow streaming responses up to 30 seconds
export const maxDuration = 30;

export async function POST(req: Request) {
  const { messages }: { messages: UIMessage[] } = await req.json();

  const result = streamText({
    model: anthropic("claude-sonnet-4-6"),
    system: aiSystemPrompt + `\n\nIMPORTANT: At the very end of every response, add exactly 3 follow-up question suggestions the user might want to ask next. Format them on their own line starting with "<<<FOLLOWUPS>>>" then each question on a new line starting with "- ". Example:
<<<FOLLOWUPS>>>
- What's your favorite project you've worked on?
- How did you get into AI?
- What's your tech stack?

These must ALWAYS be included and ALWAYS be the last thing in your response.`,
    messages: await convertToModelMessages(messages),
  });

  return result.toUIMessageStreamResponse();
}
